function hingePlan(d){
 d=Number(d);
 if(!Number.isFinite(d)||d<=0)return{ok:false,reason:"Nieprawidłowa wysokość frontu.",count:0,positions:[],formulas:[]};
 if(d>2790)return{ok:false,reason:"Front z płyty przekracza maksymalną wysokość 2790 mm.",count:0,positions:[],formulas:[]};
 let N=2,edge=100;
 if(d<450){N=2;edge=80}
 else if(d<=900)N=2;
 else if(d<=1600)N=3;
 else if(d<=2000)N=4;
 else if(d<=2400)N=5;
 else N=6;
 let positions=[],formulas=[],S=null;
 if(d<450){positions=[80,d-80];formulas=["80","d − 80"]}
 else if(N===2){positions=[100,d-100];formulas=["100","d − 100"]}
 else{
   S=(d-200)/(N-1);
   positions=Array.from({length:N},(_,i)=>100+i*S);
   if(N===3)formulas=["100","d / 2","d − 100"];
   if(N===4)formulas=["100","100 + S","d − (100 + S)","d − 100"];
   if(N===5)formulas=["100","100 + S","d / 2","d − (100 + S)","d − 100"];
   if(N===6)formulas=["100","100 + S","100 + 2S","d − (100 + 2S)","d − (100 + S)","d − 100"];
 }
 return{ok:true,d,count:N,edge,S,positions:positions.map(v=>Math.round(v*10)/10),formulas,x:22.5};
}
