   const r=await Swal.fire(kmsSwalOptions({icon:"warning",title:"KOLIZJA: półka i zawias",text:msg,showCancelButton:true,showDenyButton:true,confirmButtonText:"Przestaw półkę",denyButtonText:"Przestaw zawias",cancelButtonText:"Anuluj"}));
