  const splitRect=lay.rects.get(relation.split.id),n=relation.split.children.length,g=dims().gap;
  const usable=Math.max(1,splitRect.h-g*(n-1));
  const minOther=20*Math.max(0,n-1),max=Math.max(20,Math.floor(usable-minOther));
  value=Number(value);
  if(!Number.isFinite(value)||value<20||value>max)return false;
  relation.split.children.forEach((child,index)=>{child.fixedSize=index===relation.index?value:null});
  const changed=findLeaf(state.root,id);if(changed)changed.node.hingeOverrides={};
