const gestureDistance=pts=>Math.hypot(pts[0].x-pts[1].x,pts[0].y-pts[1].y);
const gestureCenter=pts=>({x:(pts[0].x+pts[1].x)/2,y:(pts[0].y+pts[1].y)/2});
let suppressWorkspaceClickUntil=0;
function installTwoFingerZoom(el,getView,apply,oneFingerMode){
 const pointers=new Map();let lastPoint=null,lastDistance=null,lastCenter=null,moved=false;
 el.addEventListener("pointerdown",e=>{
   pointers.set(e.pointerId,{x:e.clientX,y:e.clientY});try{el.setPointerCapture(e.pointerId)}catch(_){ }
   if(pointers.size===1)lastPoint={x:e.clientX,y:e.clientY};
   if(pointers.size===2){const pts=[...pointers.values()];lastDistance=gestureDistance(pts);lastCenter=gestureCenter(pts);moved=true}
 },{passive:false});
 el.addEventListener("pointermove",e=>{
   if(!pointers.has(e.pointerId))return;pointers.set(e.pointerId,{x:e.clientX,y:e.clientY});const pts=[...pointers.values()],v=getView();
   if(pts.length===1&&lastPoint&&oneFingerMode==="rotate"){
     v.y+=(e.clientX-lastPoint.x)*.35;v.x-=(e.clientY-lastPoint.y)*.28;lastPoint={x:e.clientX,y:e.clientY};moved=true;apply();e.preventDefault();
   }else if(pts.length===2){
     const dist=gestureDistance(pts),center=gestureCenter(pts);
     if(lastDistance)v.z=clampZoom(v.z*(dist/lastDistance));
     if(lastCenter){v.tx=(v.tx||0)+(center.x-lastCenter.x);v.ty=(v.ty||0)+(center.y-lastCenter.y)}
     lastDistance=dist;lastCenter=center;moved=true;apply();updateZoomLabel();e.preventDefault();
   }
 },{passive:false});
 const end=e=>{pointers.delete(e.pointerId);if(moved)suppressWorkspaceClickUntil=Date.now()+350;if(pointers.size===1){const p=[...pointers.values()][0];lastPoint={x:p.x,y:p.y}}else lastPoint=null;if(pointers.size<2){lastDistance=null;lastCenter=null}if(!pointers.size){moved=false;persist()}};
 el.addEventListener("pointerup",end);el.addEventListener("pointercancel",end);
 el.addEventListener("wheel",e=>{e.preventDefault();const v=getView();v.z=clampZoom(v.z+(e.deltaY<0?.1:-.1));apply();updateZoomLabel();persist()},{passive:false});
 el.addEventListener("dblclick",e=>{e.preventDefault();resetCurrentView()},{passive:false});
 el.addEventListener("click",e=>{if(Date.now()<suppressWorkspaceClickUntil){e.preventDefault();e.stopPropagation()}},true);
}
installTwoFingerZoom($("view2d"),()=>state.view2d,apply2d,"select");
installTwoFingerZoom($("view3d"),()=>state.view3d,apply3d,"rotate");
